// refreshIfStale serializes refresh attempts and skips the network call if a
// concurrent caller already rotated the token while this goroutine was waiting
// on the lock. authHeaderBefore is the Authorization value the caller computed
// before its 401 — if c.Config.AuthHeader() has since changed, the rotation
// already happened and we just let the caller retry with the fresh value.
func (c *Client) refreshIfStale(authHeaderBefore string) error {
	c.refreshMu.Lock()
	defer c.refreshMu.Unlock()
	if c.Config != nil && c.Config.AuthHeader() != authHeaderBefore && c.Config.AuthHeader() != "" {
		return nil
	}
	return c.refreshLocked()
}

